    return {"size": len(image)}

# All other files — use UploadFile
@app.post("/document/")
async def upload_document(file: UploadFile):
    content = await file.read()
    return {"filename": file.filename, "size": len(content)}

from typing import List

@app.post("/uploads/")
async def upload_multiple(files: List[UploadFile] = File(...)):
    results = []
    for file in files:
        content = await file.read()
        results.append({
            "filename": file.filename,
            "content_type": file.content_type,
            "size": len(content)
        })
    return {"uploaded": results}

import aiofiles
from fastapi import UploadFile, File, HTTPException

UPLOAD_DIR = "/data/uploads"
CHUNK_SIZE = 64 * 1024  # 64KB chunks

@app.post("/large-upload/")
async def upload_large_file(file: UploadFile = File(...)):
    # Validate before reading any content
    if file.content_type not in {"video/mp4", "video/quicktime", "video/x-msvideo"}:
        raise HTTPException(status_code=415, detail="Unsupported media type")

    safe_name = sanitize_filename(file.filename)
    destination = f"{UPLOAD_DIR}/{safe_name}"
    total_bytes = 0
    max_size = 500 * 1024 * 1024  # 500MB limit

    try:
        async with aiofiles.open(destination, "wb") as out_file:
            while True:
                chunk = await file.read(CHUNK_SIZE)
                if not chunk:
                    break
                total_bytes += len(chunk)
                if total_bytes > max_size:
                    raise HTTPException(
                        status_code=413,
                        detail=f"File exceeds maximum size of {max_size // (1024*1024)}MB"
                    )
                await out_file.write(chunk)
    except HTTPException:
        # Clean up partial file
        import os
        if os.path.exists(destination):
            os.remove(destination)
        raise

    return {"filename": safe_name, "size_bytes": total_bytes}

ALLOWED_IMAGE_TYPES = {"image/jpeg", "image/png", "image/gif", "image/webp"}

@app.post("/avatar/")
async def upload_avatar(file: UploadFile = File(...)):
    # First check: MIME type (fast but spoofable)
    if file.content_type not in ALLOWED_IMAGE_TYPES:
        raise HTTPException(
            status_code=415,
            detail=f"Unsupported type. Allowed: {', '.join(ALLOWED_IMAGE_TYPES)}"
        )

    content = await file.read()

    # Second check: magic bytes (reliable)
    if not is_valid_image(content):
        raise HTTPException(status_code=400, detail="File content does not match declared type")

    return {"filename": file.filename, "size": len(content)}

def is_valid_image(content: bytes) -> bool:
    """Validate image files by their magic bytes."""
    signatures = {
        b'\xff\xd8\xff': 'JPEG',
        b'\x89PNG\r\n\x1a\n': 'PNG',
        b'GIF87a': 'GIF',
        b'GIF89a': 'GIF',
        b'RIFF': 'WEBP',  # WebP starts with RIFF....WEBP
    }
    for sig, fmt in signatures.items():
        if content.startswith(sig):
            if fmt == 'WEBP' and content[8:12] != b'WEBP':
                continue
            return True
    return False

def get_file_type(content: bytes) -> str | None:
    """Return detected file type from magic bytes."""
    if content[:3] == b'\xff\xd8\xff':
        return 'jpeg'
    if content[:8] == b'\x89PNG\r\n\x1a\n':
        return 'png'
    if content[:4] in (b'GIF8', ):
        return 'gif'
    if content[:4] == b'%PDF':
        return 'pdf'
    if content[:4] == b'PK\x03\x04':
        return 'zip'  # Also .docx, .xlsx, .pptx
    return None

import magic

